local M = {}

function M.animation_line_replace(line, target, replace, frequency)
  return string.gsub(line, target, function(c)
    local prob = math.random()
    if prob <= frequency then
      return replace
    end
    return c
  end)
end

--- generates a series of similarly styled frames containing mostly the same
--- text with a few random modifications repeated over several frames, this way
--- we can pass to the veil's animate function easily and get a nice looking
--- header.
---@param base_frame table a collection of strings as line items in a table
---which together forms the full base splash image to use.
---@param opts { target: string?, replace: string?, frequency: number? } options that
---describe how the animation generation should proceed. Valid field of the opts
---table are:
---1. pattern: the pattern that should be randomly replaced
---2. with: the substitution values
---3. frequency: proportion of the line content that should be subject to
---replacement.
function M.generate_animation_frame(base_frame, opts)
  opts = opts or {}
  local replace = opts.target ~= nil and opts.target or [[.]]
  local replace_with = opts.replace and opts.replace or [[*]]
  local frequency = opts.frequency ~= nil and opts.frequency or 0.05 --5% replacement
  local res = vim.tbl_map(function(f)
    return M.animation_line_replace(f, replace, replace_with, frequency)
  end, base_frame)

  return res
end

--- generates a series of frames that can be presented in sequence to create an
--- ASCII-animated videographic content.
---@param base_frame string[] a collection of lines which together form a
---general picture
---@param opts { n_frame: integer?, target: string?, replace: string?, frequency: number?}
---@return (string[])[]
function M.generate_animation(base_frame, opts)
  local n_repeat = opts.n_frame ~= nil and opts.n_frame or 1
  local mapto = require("util.table").range({
    start = 1,
    stop = n_repeat,
    step = 1,
    populate = function(i)
      return M.generate_animation_frame(base_frame, opts)
    end,
  })
  return mapto
end

